// Replicating the celsius_to_f forged tool logic (F = C × 9/5 + 32, rounded to 2dp)
function celsius_to_f(celsius) {
  var fahrenheit = Math.round(((celsius * 9 / 5) + 32) * 100) / 100;
  return { celsius: celsius, fahrenheit: fahrenheit };
}

var result = celsius_to_f(100);
